diffs.replacement:
{
  "name": "Samsul's Grocery (সামসুল'স গ্রোসরি)",
  "description": "একটি আধুনিক অনলাইন গ্রোসরি শপ যা বদলগাছী, নওগাঁর স্থানীয় গ্রাহকদের জন্য তৈরি। চাল, ডাল, শাক-সবজি সহ নিত্যপ্রয়োজনীয় পণ্য সহজে কিনুন।",
  "requestFramePermissions": [
    "camera",
    "geolocation"
  ]
}

export enum Category {
  RICE = 'চাল',
  OIL = 'তেল',
  VEGETABLES = 'শাক-সবজি',
  FRUITS = 'ফল',
  SNACKS = 'নাস্তা',
  BEVERAGES = 'পানীয়',
  HOUSEHOLD = 'গৃহস্থালি',
  ALL = 'সব পণ্য'
}

export interface Product {
  id: string;
  name: string;
  price: number;
  unit: string;
  category: Category;
  image: string;
  description: string;
  stock: number;
}

export interface CartItem {
  product: Product;
  quantity: number;
}

export interface Order {
  id: string;
  customerName: string;
  phone: string;
  address: string;
  items: CartItem[];
  total: number;
  status: 'Pending' | 'Delivered' | 'Cancelled';
  date: string;
}

export type ViewType = 'STORE' | 'ADMIN' | 'CHECKOUT' | 'ABOUT';

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { ShoppingCart, User, Store, Info, Phone, Search, Menu, X, Trash2, Plus, Minus, ArrowRight, Settings } from 'lucide-react';
import { ViewType, Category, Product, CartItem, Order } from './types';
import { INITIAL_PRODUCTS } from './data';
import AdminPanel from './components/AdminPanel';
import CartSidebar from './components/CartSidebar';
import ProductCard from './components/ProductCard';

const App: React.FC = () => {
  const [view, setView] = useState<ViewType>('STORE');
  const [products, setProducts] = useState<Product[]>(() => {
    const saved = localStorage.getItem('samsul_products');
    return saved ? JSON.parse(saved) : INITIAL_PRODUCTS;
  });
  const [cart, setCart] = useState<CartItem[]>([]);
  const [activeCategory, setActiveCategory] = useState<Category>(Category.ALL);
  const [searchQuery, setSearchQuery] = useState('');
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [orders, setOrders] = useState<Order[]>(() => {
    const saved = localStorage.getItem('samsul_orders');
    return saved ? JSON.parse(saved) : [];
  });

  // Sync state to local storage
  useEffect(() => {
    localStorage.setItem('samsul_products', JSON.stringify(products));
  }, [products]);

  useEffect(() => {
    localStorage.setItem('samsul_orders', JSON.stringify(orders));
  }, [orders]);

  const addToCart = useCallback((product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.product.id === product.id);
      if (existing) {
        return prev.map(item => 
          item.product.id === product.id ? { ...item, quantity: item.quantity + 1 } : item
        );
      }
      return [...prev, { product, quantity: 1 }];
    });
    setIsCartOpen(true);
  }, []);

  const removeFromCart = useCallback((productId: string) => {
    setCart(prev => prev.filter(item => item.product.id !== productId));
  }, []);

  const updateQuantity = useCallback((productId: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.product.id === productId) {
        const newQty = Math.max(1, item.quantity + delta);
        return { ...item, quantity: newQty };
      }
      return item;
    }));
  }, []);

  const cartTotal = useMemo(() => cart.reduce((sum, item) => sum + (item.product.price * item.quantity), 0), [cart]);

  const filteredProducts = useMemo(() => {
    return products.filter(p => {
      const matchesCategory = activeCategory === Category.ALL || p.category === activeCategory;
      const matchesSearch = p.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
                           p.description.toLowerCase().includes(searchQuery.toLowerCase());
      return matchesCategory && matchesSearch;
    });
  }, [products, activeCategory, searchQuery]);

  const placeOrder = (customerData: { name: string, phone: string, address: string }) => {
    const newOrder: Order = {
      id: Math.random().toString(36).substr(2, 9),
      customerName: customerData.name,
      phone: customerData.phone,
      address: customerData.address,
      items: [...cart],
      total: cartTotal,
      status: 'Pending',
      date: new Date().toLocaleDateString('bn-BD')
    };
    setOrders(prev => [newOrder, ...prev]);
    setCart([]);
    setView('STORE');
    alert('আপনার অর্ডারটি সফলভাবে সম্পন্ন হয়েছে! আমরা শীঘ্রই আপনার সাথে যোগাযোগ করব।');
  };

  return (
    <div className="min-h-screen flex flex-col">
      {/* Header */}
      <header className="sticky top-0 z-40 bg-white border-b shadow-sm">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between items-center h-20">
            <div className="flex items-center gap-4 cursor-pointer" onClick={() => setView('STORE')}>
              <div className="bg-emerald-600 p-2 rounded-lg text-white">
                <Store size={28} />
              </div>
              <div className="hidden sm:block">
                <h1 className="text-2xl font-bold text-emerald-800 leading-none">সামসুল'স গ্রোসরি</h1>
                <p className="text-xs text-gray-500 font-medium">চার মাথার মোড়, বদলগাছী</p>
              </div>
            </div>

            {/* Desktop Search */}
            <div className="hidden md:flex flex-1 max-w-lg mx-8">
              <div className="relative w-full">
                <input
                  type="text"
                  placeholder="পণ্য খুঁজুন (যেমন: চাল, ডাল...)"
                  className="w-full pl-10 pr-4 py-2 rounded-full border border-gray-300 focus:outline-none focus:ring-2 focus:ring-emerald-500 focus:border-transparent transition"
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                />
                <Search className="absolute left-3 top-2.5 text-gray-400" size={18} />
              </div>
            </div>

            {/* Navigation & Actions */}
            <div className="flex items-center gap-2 sm:gap-4">
              <button 
                onClick={() => setView('ADMIN')}
                className="hidden sm:flex items-center gap-2 text-gray-600 hover:text-emerald-700 transition"
              >
                <Settings size={20} />
                <span className="font-medium">অ্যাডমিন</span>
              </button>

              <button 
                onClick={() => setIsCartOpen(true)}
                className="relative p-2 text-gray-700 hover:text-emerald-600 transition"
              >
                <ShoppingCart size={24} />
                {cart.length > 0 && (
                  <span className="absolute -top-1 -right-1 bg-red-500 text-white text-[10px] font-bold w-5 h-5 flex items-center justify-center rounded-full animate-bounce">
                    {cart.length}
                  </span>
                )}
              </button>

              <button 
                className="md:hidden p-2 text-gray-700"
                onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
              >
                {isMobileMenuOpen ? <X size={24} /> : <Menu size={24} />}
              </button>
            </div>
          </div>
        </div>
      </header>

      {/* Mobile Menu */}
      {isMobileMenuOpen && (
        <div className="md:hidden bg-white border-b absolute top-20 left-0 w-full z-30 animate-fade-in">
          <div className="px-4 py-4 space-y-4">
            <div className="relative">
              <input
                type="text"
                placeholder="পণ্য খুঁজুন..."
                className="w-full pl-10 pr-4 py-2 rounded-lg border border-gray-300"
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
              />
              <Search className="absolute left-3 top-2.5 text-gray-400" size={18} />
            </div>
            <nav className="flex flex-col gap-3">
              <button onClick={() => { setView('STORE'); setIsMobileMenuOpen(false); }} className="flex items-center gap-3 py-2 text-lg font-medium text-gray-700 hover:text-emerald-600 transition">
                <Store size={20} /> হোম পেজ
              </button>
              <button onClick={() => { setView('ADMIN'); setIsMobileMenuOpen(false); }} className="flex items-center gap-3 py-2 text-lg font-medium text-gray-700 hover:text-emerald-600 transition">
                <Settings size={20} /> অ্যাডমিন ড্যাশবোর্ড
              </button>
              <button onClick={() => { setView('ABOUT'); setIsMobileMenuOpen(false); }} className="flex items-center gap-3 py-2 text-lg font-medium text-gray-700 hover:text-emerald-600 transition">
                <Info size={20} /> আমাদের সম্পর্কে
              </button>
            </nav>
          </div>
        </div>
      )}

      {/* Main Content */}
      <main className="flex-grow">
        {view === 'STORE' && (
          <div className="max-w-7xl mx-auto px-4 py-6 sm:px-6 lg:px-8">
            {/* Hero Section */}
            <div className="relative rounded-2xl overflow-hidden mb-8 h-48 sm:h-64 md:h-80 shadow-lg group">
              <img 
                src="https://picsum.photos/seed/grocery-banner/1200/400" 
                alt="Banner" 
                className="w-full h-full object-cover transform group-hover:scale-105 transition duration-700"
              />
              <div className="absolute inset-0 bg-gradient-to-r from-emerald-900/80 to-transparent flex flex-col justify-center px-8 sm:px-12">
                <h2 className="text-3xl sm:text-4xl md:text-5xl font-extrabold text-white mb-2 leading-tight">
                  টাটকা ও সতেজ বাজার <br/> একদম ঘরের দরজায়!
                </h2>
                <p className="text-emerald-100 text-lg sm:text-xl font-medium max-w-md">
                  বদলগাছীর সবচেয়ে বিশ্বস্ত অনলাইন গ্রোসরি শপ।
                </p>
                <div className="mt-6 flex gap-4">
                  <button onClick={() => document.getElementById('products')?.scrollIntoView({ behavior: 'smooth' })} className="bg-white text-emerald-800 px-6 py-2.5 rounded-full font-bold hover:bg-emerald-50 transition shadow-md">
                    বাজার শুরু করুন
                  </button>
                  <a href="https://wa.me/8801700000000" target="_blank" rel="noreferrer" className="bg-green-500 text-white px-6 py-2.5 rounded-full font-bold flex items-center gap-2 hover:bg-green-600 transition shadow-md">
                    <Phone size={18} /> হোয়াটস্যাপ
                  </a>
                </div>
              </div>
            </div>

            {/* Categories */}
            <div className="mb-8 overflow-x-auto no-scrollbar">
              <div className="flex gap-4 pb-2">
                {Object.values(Category).map((cat) => (
                  <button
                    key={cat}
                    onClick={() => setActiveCategory(cat)}
                    className={`whitespace-nowrap px-6 py-2 rounded-full font-semibold transition shadow-sm border ${
                      activeCategory === cat 
                      ? 'bg-emerald-600 text-white border-emerald-600' 
                      : 'bg-white text-gray-600 border-gray-200 hover:border-emerald-300 hover:text-emerald-600'
                    }`}
                  >
                    {cat}
                  </button>
                ))}
              </div>
            </div>

            {/* Products Grid */}
            <div id="products">
              <div className="flex justify-between items-center mb-6">
                <h3 className="text-2xl font-bold text-gray-800">
                  {activeCategory === Category.ALL ? 'সকল পণ্য' : activeCategory}
                </h3>
                <p className="text-gray-500 font-medium">{filteredProducts.length} টি পণ্য পাওয়া গেছে</p>
              </div>

              {filteredProducts.length > 0 ? (
                <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-4 md:gap-6">
                  {filteredProducts.map(product => (
                    <ProductCard key={product.id} product={product} onAddToCart={addToCart} />
                  ))}
                </div>
              ) : (
                <div className="py-20 text-center">
                  <div className="text-gray-300 mb-4 flex justify-center">
                    <Search size={64} />
                  </div>
                  <p className="text-xl text-gray-500 font-medium">দুঃখিত! এই ক্যাটাগরিতে কোন পণ্য পাওয়া যায়নি।</p>
                </div>
              )}
            </div>
          </div>
        )}

        {view === 'ADMIN' && (
          <AdminPanel 
            products={products} 
            setProducts={setProducts} 
            orders={orders} 
            setOrders={setOrders}
          />
        )}

        {view === 'CHECKOUT' && (
          <div className="max-w-2xl mx-auto px-4 py-12">
            <h2 className="text-3xl font-bold text-gray-800 mb-8 border-b pb-4">অর্ডার নিশ্চিত করুন</h2>
            <form onSubmit={(e) => {
              e.preventDefault();
              const formData = new FormData(e.currentTarget);
              placeOrder({
                name: formData.get('name') as string,
                phone: formData.get('phone') as string,
                address: formData.get('address') as string,
              });
            }} className="space-y-6 bg-white p-8 rounded-2xl shadow-sm border">
              <div>
                <label className="block text-sm font-bold text-gray-700 mb-2">আপনার নাম *</label>
                <input required name="name" type="text" className="w-full px-4 py-3 rounded-xl border border-gray-300 focus:ring-2 focus:ring-emerald-500 outline-none transition" placeholder="পুরো নাম লিখুন" />
              </div>
              <div>
                <label className="block text-sm font-bold text-gray-700 mb-2">মোবাইল নম্বর *</label>
                <input required name="phone" type="tel" className="w-full px-4 py-3 rounded-xl border border-gray-300 focus:ring-2 focus:ring-emerald-500 outline-none transition" placeholder="০১৭০০-০০০০০০" />
              </div>
              <div>
                <label className="block text-sm font-bold text-gray-700 mb-2">পূর্ণ ঠিকানা *</label>
                <textarea required name="address" rows={3} className="w-full px-4 py-3 rounded-xl border border-gray-300 focus:ring-2 focus:ring-emerald-500 outline-none transition" placeholder="বাসা নং, গ্রাম, এলাকা"></textarea>
              </div>
              <div className="p-4 bg-emerald-50 rounded-xl border border-emerald-100">
                <p className="text-emerald-800 font-bold mb-1">পেমেন্ট মেথড:</p>
                <div className="flex items-center gap-2 text-emerald-700">
                  <div className="w-2 h-2 rounded-full bg-emerald-600"></div>
                  <span>ক্যাশ অন ডেলিভারি (পণ্য হাতে পেয়ে টাকা দিন)</span>
                </div>
              </div>
              <div className="border-t pt-4 mt-6">
                <div className="flex justify-between items-center text-xl font-bold mb-6">
                  <span>মোট বিল:</span>
                  <span className="text-emerald-600">৳ {cartTotal}</span>
                </div>
                <button type="submit" className="w-full bg-emerald-600 text-white py-4 rounded-xl font-bold text-lg hover:bg-emerald-700 transition flex items-center justify-center gap-2 shadow-lg shadow-emerald-200">
                  অর্ডার প্লেস করুন <ArrowRight size={20} />
                </button>
              </div>
            </form>
          </div>
        )}

        {view === 'ABOUT' && (
          <div className="max-w-4xl mx-auto px-4 py-12">
            <h2 className="text-3xl font-bold text-gray-800 mb-6">সামসুল'স গ্রোসরি সম্পর্কে</h2>
            <div className="prose prose-emerald lg:prose-xl bg-white p-8 rounded-2xl shadow-sm border">
              <p className="text-lg text-gray-600 leading-relaxed mb-6">
                সামসুল'স গ্রোসরি বদলগাছী, নওগাঁর একটি স্থানীয় উদ্যোগ। আমরা বিশ্বাস করি গুণমান এবং বিশ্বস্ততায়। চার মাথার মোড়ে আমাদের দোকানের সুনাম আজ ঘরে ঘরে। গ্রাহকদের কথা চিন্তা করে আমরা এখন অনলাইনে আমাদের সেবা শুরু করেছি।
              </p>
              <h3 className="text-2xl font-bold text-emerald-800 mb-4">কেন আমাদের পছন্দ করবেন?</h3>
              <ul className="space-y-4 text-gray-700">
                <li className="flex items-start gap-3">
                  <div className="bg-emerald-100 p-1 rounded-full text-emerald-600 mt-1"><Plus size={16} /></div>
                  <span>টাটকা ও সতেজ শাক-সবজি সরাসরি কৃষকের কাছ থেকে সংগৃহীত।</span>
                </li>
                <li className="flex items-start gap-3">
                  <div className="bg-emerald-100 p-1 rounded-full text-emerald-600 mt-1"><Plus size={16} /></div>
                  <span>দ্রুত হোম ডেলিভারি সেবা।</span>
                </li>
                <li className="flex items-start gap-3">
                  <div className="bg-emerald-100 p-1 rounded-full text-emerald-600 mt-1"><Plus size={16} /></div>
                  <span>ন্যায্য মূল্য এবং সঠিক ওজনের নিশ্চয়তা।</span>
                </li>
              </ul>

              <div className="mt-12">
                <h3 className="text-2xl font-bold text-emerald-800 mb-4">আমাদের অবস্থান</h3>
                <div className="h-64 rounded-xl overflow-hidden shadow-inner border bg-gray-100 flex items-center justify-center">
                  <div className="text-center p-6">
                    <Phone className="mx-auto mb-2 text-emerald-600" size={32} />
                    <p className="font-bold">চার মাথার মোড়, বদলগাছী উপজেলা, নওগাঁ</p>
                    <p className="text-gray-500 text-sm mt-1">যোগাযোগ: +৮৮০ ১৭০০ ০০০০০০</p>
                  </div>
                </div>
              </div>
            </div>
          </div>
        )}
      </main>

      {/* Footer */}
      <footer className="bg-gray-900 text-white py-12">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="grid grid-cols-1 md:grid-cols-4 gap-8">
            <div className="space-y-4">
              <h4 className="text-2xl font-bold text-emerald-400">সামসুল'স গ্রোসরি</h4>
              <p className="text-gray-400">বদলগাছী বাসীর বিশ্বস্ত কেনাকাটার ঠিকানা। আমরা দিচ্ছি ১০০% বিশুদ্ধ পণ্যের নিশ্চয়তা।</p>
            </div>
            <div>
              <h4 className="text-lg font-bold mb-4">কুইক লিঙ্ক</h4>
              <ul className="space-y-2 text-gray-400">
                <li><button onClick={() => setView('STORE')} className="hover:text-emerald-400">হোম</button></li>
                <li><button onClick={() => setView('ABOUT')} className="hover:text-emerald-400">আমাদের সম্পর্কে</button></li>
                <li><button className="hover:text-emerald-400">অফার সমূহ</button></li>
              </ul>
            </div>
            <div>
              <h4 className="text-lg font-bold mb-4">ক্যাটাগরি</h4>
              <ul className="space-y-2 text-gray-400">
                {Object.values(Category).slice(0, 5).map(cat => (
                  <li key={cat}><button onClick={() => {setActiveCategory(cat); setView('STORE');}} className="hover:text-emerald-400">{cat}</button></li>
                ))}
              </ul>
            </div>
            <div>
              <h4 className="text-lg font-bold mb-4">সরাসরি যোগাযোগ</h4>
              <p className="text-gray-400 mb-2">ঠিকানা: চার মাথার মোড়, বদলগাছী</p>
              <p className="text-gray-400 mb-2">ফোন: +৮৮০ ১৭০০ ০০০০০০</p>
              <div className="flex gap-4 mt-4">
                <a href="#" className="bg-white/10 p-2 rounded-full hover:bg-emerald-600 transition">
                  <Phone size={20} />
                </a>
                <a href="#" className="bg-white/10 p-2 rounded-full hover:bg-emerald-600 transition">
                  <User size={20} />
                </a>
              </div>
            </div>
          </div>
          <div className="border-t border-white/10 mt-12 pt-8 text-center text-gray-500 text-sm">
            &copy; ২০২৪ সামসুল'স গ্রোসরি - সকল স্বত্ব সংরক্ষিত।
          </div>
        </div>
      </footer>

      {/* Cart Sidebar */}
      <CartSidebar 
        isOpen={isCartOpen} 
        onClose={() => setIsCartOpen(false)} 
        cart={cart} 
        updateQuantity={updateQuantity} 
        removeFromCart={removeFromCart} 
        onCheckout={() => { setIsCartOpen(false); setView('CHECKOUT'); }} 
      />

