                        >
                          <CheckCircle size={16} /> ডেলিভারি সম্পন্ন
                        </button>
                      )}
                      {order.status === 'Pending' && (
                        <button 
                          onClick={() => updateOrderStatus(order.id, 'Cancelled')}
                          className="bg-red-50 text-red-600 px-4 py-2 rounded-lg text-sm font-bold hover:bg-red-100 transition"
                        >
