                    onChange={e => setSlideFormData(p => ({...p, buttonText: e.target.value}))} 
                    className="w-full px-4 py-3 border-2 border-gray-100 rounded-xl text-gray-800 bg-white focus:border-emerald-500 focus:ring-4 focus:ring-emerald-50 outline-none transition font-medium placeholder:text-gray-300 shadow-sm" 
                    placeholder="যেমন: অফার দেখুন" 
                  />
                </div>
              </div>

