                >
                  ফিরে যান
                </button>
                <button 
                  type="submit" 
                  className="flex-1 bg-emerald-600 text-white px-6 py-4 rounded-2xl font-black text-lg hover:bg-emerald-700 shadow-lg shadow-emerald-200 transition transform active:scale-95 flex items-center justify-center gap-2"
                >
                  {editingSlide ? <CheckCircle size={20} /> : <Plus size={20} />}
                  {editingSlide ? 'আপডেট সম্পন্ন করুন' : 'নতুন স্লাইড যোগ করুন'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
