              </button>
              <button 
                className="md:hidden p-2.5 text-gray-700 hover:bg-gray-100 rounded-full transition"
                onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
              >
                {isMobileMenuOpen ? <X size={24} /> : <Menu size={24} />}
              </button>
            </div>
          </div>
        </div>
      </header>

      {/* Mobile Menu Overlay */}
      {isMobileMenuOpen && (
        <div className="md:hidden bg-white border-b absolute top-20 left-0 w-full z-30 animate-fade-in shadow-xl p-6">
          <nav className="flex flex-col gap-2">
            <NavItem label="হোম পেজ" viewTarget="STORE" icon={<Store size={20} />} />
            <NavItem label="আমাদের সম্পর্কে" viewTarget="ABOUT" icon={<Info size={20} />} />
            <NavItem label="অ্যাডমিন ড্যাশবোর্ড" viewTarget="ADMIN" icon={<Settings size={20} />} />
          </nav>
        </div>
      )}

      <main className="flex-grow">
        {view === 'STORE' && (
          <div className="max-w-7xl mx-auto px-4 py-6 sm:px-6 lg:px-8 animate-fade-in">
            {/* Slider Section */}
            {slides.length > 0 && (
              <div className="relative rounded-3xl overflow-hidden mb-10 h-56 sm:h-72 md:h-96 shadow-xl bg-emerald-900">
                {slides.map((slide, index) => (
                  <div key={slide.id} className={`absolute inset-0 transition-all duration-1000 ${index === currentSlide ? 'opacity-100' : 'opacity-0 pointer-events-none'}`}>
                    <img src={slide.image} alt={slide.title} className="w-full h-full object-cover opacity-60" />
                    <div className="absolute inset-0 bg-gradient-to-r from-emerald-900/80 flex flex-col justify-center px-8 sm:px-16">
