import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { ShoppingCart, Store, Info, Phone, Search, Menu, X, ArrowRight, Settings } from 'lucide-react';
import { ViewType, Category, Product, CartItem, Order, Slide } from './types';
import { INITIAL_PRODUCTS, INITIAL_SLIDES } from './data';
import { supabase } from './supabase';
import AdminPanel from './components/AdminPanel';
import CartSidebar from './components/CartSidebar';
import ProductCard from './components/ProductCard';

const App: React.FC = () => {
  const [view, setView] = useState<ViewType>('STORE');
  const [products, setProducts] = useState<Product[]>([]);
  const [slides, setSlides] = useState<Slide[]>([]);
  const [orders, setOrders] = useState<Order[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  const [cart, setCart] = useState<CartItem[]>([]);
  const [activeCategory, setActiveCategory] = useState<Category>(Category.ALL);
  const [searchQuery, setSearchQuery] = useState('');
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [currentSlide, setCurrentSlide] = useState(0);

  // Fetch data from Supabase on mount
  useEffect(() => {
    const fetchData = async () => {
      setIsLoading(true);
      try {
        const { data: prodData } = await supabase.from('products').select('*');
        const { data: slideData } = await supabase.from('slides').select('*');
        const { data: orderData } = await supabase.from('orders').select('*').order('date', { ascending: false });

        if (prodData && prodData.length > 0) setProducts(prodData);
        else setProducts(INITIAL_PRODUCTS); // Fallback

        if (slideData && slideData.length > 0) setSlides(slideData);
        else setSlides(INITIAL_SLIDES); // Fallback

        if (orderData) setOrders(orderData);
      } catch (error) {
        console.error('Error fetching data:', error);
        setProducts(INITIAL_PRODUCTS);
        setSlides(INITIAL_SLIDES);
      } finally {
        setIsLoading(false);
      }
    };

    fetchData();
  }, []);

  useEffect(() => {
    if (view === 'STORE' && slides.length > 0) {
      const timer = setInterval(() => {
        setCurrentSlide(prev => (prev + 1) % slides.length);
      }, 5000);
      return () => clearInterval(timer);
    }
  }, [view, slides.length]);

  const addToCart = useCallback((product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.product.id === product.id);
      if (existing) {
        return prev.map(item => 
          item.product.id === product.id ? { ...item, quantity: item.quantity + 1 } : item
        );
      }
      return [...prev, { product, quantity: 1 }];
    });
    setIsCartOpen(true);
  }, []);

  const removeFromCart = useCallback((productId: string) => {
    setCart(prev => prev.filter(item => item.product.id !== productId));
  }, []);

  const updateQuantity = useCallback((productId: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.product.id === productId) {
        const newQty = Math.max(1, item.quantity + delta);
        return { ...item, quantity: newQty };
      }
      return item;
    }));
  }, []);

  const cartTotal = useMemo(() => cart.reduce((sum, item) => sum + (item.product.price * item.quantity), 0), [cart]);

  const filteredProducts = useMemo(() => {
    return products.filter(p => {
      const matchesCategory = activeCategory === Category.ALL || p.category === activeCategory;
      const matchesSearch = p.name.toLowerCase().includes(searchQuery.toLowerCase());
      return matchesCategory && matchesSearch;
    });
  }, [products, activeCategory, searchQuery]);

  const placeOrder = async (customerData: { name: string, phone: string, address: string }) => {
    const newOrder = {
      customerName: customerData.name,
      phone: customerData.phone,
      address: customerData.address,
      items: cart,
      total: cartTotal,
      status: 'Pending',
      date: new Date().toISOString()
    };

    const { data, error } = await supabase.from('orders').insert([newOrder]).select();

    if (error) {
      alert('অর্ডার সেভ করতে সমস্যা হয়েছে। আবার চেষ্টা করুন।');
    } else {
      setOrders(prev => [data[0], ...prev]);
      setCart([]);
      setView('STORE');
      alert('আপনার অর্ডারটি সফলভাবে সম্পন্ন হয়েছে!');
    }
  };

  const NavItem: React.FC<{ label: string; viewTarget: ViewType; icon?: React.ReactNode }> = ({ label, viewTarget, icon }) => (
    <button 
      onClick={() => { setView(viewTarget); setIsMobileMenuOpen(false); }}
      className={`flex items-center gap-2 px-3 py-2 rounded-lg font-medium transition-all duration-200 ${
        view === viewTarget ? 'text-emerald-700 bg-emerald-50' : 'text-gray-600 hover:text-emerald-600 hover:bg-gray-50'
      }`}
    >
      {icon}
      <span>{label}</span>
    </button>
  );

  if (isLoading) {
    return (
      <div className="h-screen flex flex-col items-center justify-center bg-white">
        <div className="w-16 h-16 border-4 border-emerald-600 border-t-transparent rounded-full animate-spin mb-4"></div>
        <p className="text-emerald-800 font-bold">লোড হচ্ছে...</p>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex flex-col">
      <header className="sticky top-0 z-40 bg-white border-b shadow-sm">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between items-center h-20">
            <div className="flex items-center gap-4 cursor-pointer" onClick={() => setView('STORE')}>
              <div className="bg-emerald-600 p-2 rounded-lg text-white shadow-md"><Store size={28} /></div>
              <div className="hidden sm:block">
                <h1 className="text-xl font-bold text-emerald-800 leading-none">সামসুল'স গ্রোসরি</h1>
                <p className="text-[10px] text-gray-500 font-medium mt-1">বদলগাছী, নওগাঁ</p>
              </div>
            </div>

            <div className="flex items-center gap-4">
              <nav className="hidden xl:flex items-center gap-1">
                <NavItem label="হোম" viewTarget="STORE" icon={<Store size={18} />} />
                <NavItem label="অ্যাডমিন" viewTarget="ADMIN" icon={<Settings size={18} />} />
              </nav>
              <button onClick={() => setIsCartOpen(true)} className="relative p-2.5 text-gray-700 hover:bg-emerald-50 rounded-full transition">
                <ShoppingCart size={24} />
                {cart.length > 0 && <span className="absolute top-1 right-1 bg-red-500 text-white text-[10px] font-bold w-5 h-5 flex items-center justify-center rounded-full border-2 border-white">{cart.length}</span>}
              </button>
              <button className="md:hidden p-2.5 text-gray-700" onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}><Menu size={24} /></button>
            </div>
          </div>
        </div>
      </header>

      {isMobileMenuOpen && (
        <div className="md:hidden bg-white border-b shadow-xl p-6 absolute top-20 w-full z-30">
          <nav className="flex flex-col gap-2">
            <NavItem label="হোম পেজ" viewTarget="STORE" icon={<Store size={20} />} />
            <NavItem label="অ্যাডমিন" viewTarget="ADMIN" icon={<Settings size={20} />} />
          </nav>
        </div>
      )}

      <main className="flex-grow">
        {view === 'STORE' && (
          <div className="max-w-7xl mx-auto px-4 py-6 sm:px-6 lg:px-8 animate-fade-in">
            {slides.length > 0 && (
              <div className="relative rounded-3xl overflow-hidden mb-10 h-64 md:h-96 shadow-xl bg-emerald-900">
                {slides.map((slide, index) => (
                  <div key={slide.id} className={`absolute inset-0 transition-opacity duration-1000 ${index === currentSlide ? 'opacity-100' : 'opacity-0 pointer-events-none'}`}>
                    <img src={slide.image} alt={slide.title} className="w-full h-full object-cover opacity-60" />
                    <div className="absolute inset-0 bg-gradient-to-r from-emerald-900/80 flex flex-col justify-center px-12">
                      <h2 className="text-3xl md:text-5xl font-black text-white mb-4">{slide.title}</h2>
                      <p className="text-emerald-100 text-lg mb-8 max-w-lg">{slide.subtitle}</p>
                      <button onClick={() => setView('STORE')} className="bg-white text-emerald-900 px-8 py-3 rounded-full font-black w-fit">{slide.buttonText}</button>
                    </div>
                  </div>
                ))}
              </div>
            )}

            <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-6 gap-4">
              {filteredProducts.map(product => (
                <ProductCard key={product.id} product={product} onAddToCart={addToCart} />
              ))}
            </div>
          </div>
        )}

        {view === 'ADMIN' && (
          <AdminPanel 
            products={products} setProducts={setProducts} 
            slides={slides} setSlides={setSlides}
            orders={orders} setOrders={setOrders}
          />
        )}

        {view === 'CHECKOUT' && (
          <div className="max-w-xl mx-auto py-12 px-4 animate-fade-in">
            <h2 className="text-3xl font-black mb-8 text-center">চেকআউট</h2>
            <form onSubmit={(e) => {
              e.preventDefault();
              const fd = new FormData(e.currentTarget);
              placeOrder({
                name: fd.get('name') as string,
                phone: fd.get('phone') as string,
                address: fd.get('address') as string,
              });
            }} className="bg-white p-8 rounded-3xl shadow-xl space-y-4">
              <input name="name" required className="w-full p-4 border rounded-xl" placeholder="নাম" />
              <input name="phone" required className="w-full p-4 border rounded-xl" placeholder="মোবাইল" />
              <textarea name="address" required className="w-full p-4 border rounded-xl" placeholder="ঠিকানা" rows={3}></textarea>
              <div className="flex justify-between text-xl font-bold pt-4"><span>মোট:</span><span>৳ {cartTotal}</span></div>
              <button className="w-full bg-emerald-600 text-white py-4 rounded-xl font-black text-lg">অর্ডার করুন</button>
            </form>
          </div>
        )}
      </main>

      <footer className="bg-gray-900 text-white py-8 text-center opacity-70">
        <p>&copy; ২০২৪ সামসুল'স গ্রোসরি - বদলগাছী</p>
      </footer>

      <CartSidebar 
        isOpen={isCartOpen} onClose={() => setIsCartOpen(false)} 
        cart={cart} updateQuantity={updateQuantity} 
        removeFromCart={removeFromCart} onCheckout={() => { setIsCartOpen(false); setView('CHECKOUT'); }} 
      />
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Package, ClipboardList, TrendingUp, LogOut, Plus, Trash2 } from 'lucide-react';
import { Product, Order, Slide, Category } from '../types';
import { supabase } from '../supabase';

interface AdminPanelProps {
  products: Product[];
  setProducts: React.Dispatch<React.SetStateAction<Product[]>>;
  slides: Slide[];
  setSlides: React.Dispatch<React.SetStateAction<Slide[]>>;
  orders: Order[];
  setOrders: React.Dispatch<React.SetStateAction<Order[]>>;
}

const AdminPanel: React.FC<AdminPanelProps> = ({ products, setProducts, slides, setSlides, orders, setOrders }) => {
  const [activeTab, setActiveTab] = useState<'DASHBOARD' | 'PRODUCTS' | 'ORDERS'>('DASHBOARD');
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [password, setPassword] = useState('');

  const deleteProduct = async (id: string) => {
    const { error } = await supabase.from('products').delete().eq('id', id);
    if (!error) setProducts(prev => prev.filter(p => p.id !== id));
    else alert('ডিলিট করতে সমস্যা হয়েছে।');
  };

  const updateOrderStatus = async (id: string, status: string) => {
    const { error } = await supabase.from('orders').update({ status }).eq('id', id);
    if (!error) setOrders(prev => prev.map(o => o.id === id ? { ...o, status: status as any } : o));
  };

  if (!isAuthenticated) {
    return (
      <div className="max-w-md mx-auto my-20 p-8 bg-white rounded-2xl shadow-xl border">
        <h2 className="text-2xl font-bold text-center mb-6">অ্যাডমিন প্যানেল</h2>
        <input 
          type="password" 
          className="w-full p-4 border rounded-xl mb-4" 
          placeholder="পাসওয়ার্ড" 
          value={password}
          onChange={(e) => setPassword(e.target.value)}
        />
        <button 
          onClick={() => { if (password === 'admin123') setIsAuthenticated(true); else alert('ভুল পাসওয়ার্ড'); }}
          className="w-full bg-emerald-600 text-white py-4 rounded-xl font-bold"
        >
          লগইন
        </button>
      </div>
    );
  }

  return (
    <div className="max-w-7xl mx-auto px-4 py-8 flex flex-col md:flex-row gap-8">
      <div className="w-full md:w-64 space-y-2">
        <button onClick={() => setActiveTab('DASHBOARD')} className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl font-bold ${activeTab === 'DASHBOARD' ? 'bg-emerald-600 text-white' : 'bg-white'}`}><TrendingUp size={20} /> ড্যাশবোর্ড</button>
        <button onClick={() => setActiveTab('PRODUCTS')} className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl font-bold ${activeTab === 'PRODUCTS' ? 'bg-emerald-600 text-white' : 'bg-white'}`}><Package size={20} /> পণ্য তালিকা</button>
        <button onClick={() => setActiveTab('ORDERS')} className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl font-bold ${activeTab === 'ORDERS' ? 'bg-emerald-600 text-white' : 'bg-white'}`}><ClipboardList size={20} /> অর্ডারসমূহ</button>
        <button onClick={() => setIsAuthenticated(false)} className="w-full flex items-center gap-3 px-4 py-3 rounded-xl font-bold text-red-500"><LogOut size={20} /> লগআউট</button>
      </div>

      <div className="flex-grow space-y-6">
        {activeTab === 'DASHBOARD' && (
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <div className="bg-white p-6 rounded-2xl border">
              <p className="text-gray-400 font-bold text-xs uppercase">মোট বিক্রয়</p>
              <p className="text-3xl font-black text-emerald-700">৳ {orders.reduce((s, o) => s + o.total, 0)}</p>
            </div>
            <div className="bg-white p-6 rounded-2xl border">
              <p className="text-gray-400 font-bold text-xs uppercase">মোট অর্ডার</p>
              <p className="text-3xl font-black">{orders.length}</p>
            </div>
            <div className="bg-white p-6 rounded-2xl border">
              <p className="text-gray-400 font-bold text-xs uppercase">পণ্য সংখ্যা</p>
              <p className="text-3xl font-black">{products.length}</p>
            </div>
          </div>
        )}

        {activeTab === 'PRODUCTS' && (
          <div className="bg-white rounded-2xl border overflow-hidden">
            <div className="p-4 border-b flex justify-between items-center bg-gray-50">
              <h3 className="font-bold">পণ্যের তালিকা (DATABASE)</h3>
              <button className="bg-emerald-600 text-white px-4 py-2 rounded-lg text-sm font-bold flex items-center gap-2"><Plus size={16}/> নতুন পণ্য</button>
            </div>
            <table className="w-full">
              <thead className="bg-gray-100 text-xs font-bold text-gray-500"><tr><th className="p-4 text-left">নাম</th><th className="p-4 text-left">ক্যাটাগরি</th><th className="p-4 text-right">দাম</th><th className="p-4 text-right">অ্যাকশন</th></tr></thead>
              <tbody className="divide-y">{products.map(p => (
                <tr key={p.id}>
                  <td className="p-4 font-bold">{p.name}</td>
                  <td className="p-4 text-sm text-gray-500">{p.category}</td>
                  <td className="p-4 text-right font-black">৳ {p.price}</td>
                  <td className="p-4 text-right"><button onClick={() => deleteProduct(p.id)} className="text-red-500 hover:bg-red-50 p-2 rounded-lg"><Trash2 size={18}/></button></td>
                </tr>
              ))}</tbody>
            </table>
          </div>
        )}

        {activeTab === 'ORDERS' && (
          <div className="space-y-4">
            {orders.map(o => (
              <div key={o.id} className="bg-white p-6 rounded-2xl border flex justify-between items-center">
                <div>
                  <p className="font-black text-lg">{o.customerName}</p>
                  <p className="text-sm text-gray-500">{o.phone} | {new Date(o.date).toLocaleDateString('bn-BD')}</p>
                  <p className={`text-xs font-bold mt-2 ${o.status === 'Delivered' ? 'text-emerald-600' : 'text-amber-600'}`}>{o.status === 'Pending' ? 'অপেক্ষমান' : 'ডেলিভারি হয়েছে'}</p>
                </div>
                <div className="text-right">
                  <p className="text-xl font-black text-emerald-800 mb-2">৳ {o.total}</p>
                  {o.status === 'Pending' && <button onClick={() => updateOrderStatus(o.id, 'Delivered')} className="bg-emerald-50 text-emerald-600 px-4 py-2 rounded-lg text-xs font-bold border border-emerald-100">ডেলিভারি সম্পন্ন</button>}
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default AdminPanel;

import React, { useState } from 'react';
import { Package, ClipboardList, TrendingUp, LogOut, Plus, Trash2, X, Edit, Layout, Save } from 'lucide-react';
import { Product, Order, Slide, Category } from '../types';
import { supabase } from '../supabase';

interface AdminPanelProps {
  products: Product[];
  setProducts: React.Dispatch<React.SetStateAction<Product[]>>;
  slides: Slide[];
  setSlides: React.Dispatch<React.SetStateAction<Slide[]>>;
  orders: Order[];
  setOrders: React.Dispatch<React.SetStateAction<Order[]>>;
}

const AdminPanel: React.FC<AdminPanelProps> = ({ products, setProducts, slides, setSlides, orders, setOrders }) => {
  const [activeTab, setActiveTab] = useState<'DASHBOARD' | 'PRODUCTS' | 'ORDERS' | 'SLIDES'>('DASHBOARD');
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [password, setPassword] = useState('');

  // Modals state
  const [isProductModalOpen, setIsProductModalOpen] = useState(false);
  const [isSlideModalOpen, setIsSlideModalOpen] = useState(false);
  const [editingItem, setEditingItem] = useState<any>(null);

  // Form states
  const [productForm, setProductForm] = useState({
    name: '', price: '', unit: 'কেজি', category: Category.VEGETABLES, image: '', description: '', stock: '100'
  });
  const [slideForm, setSlideForm] = useState({
    image: '', title: '', subtitle: '', buttonText: 'বাজার শুরু করুন'
  });

  const handleProductSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const data = {
      ...productForm,
      price: parseFloat(productForm.price),
      stock: parseInt(productForm.stock)
    };

    if (editingItem) {
      const { error } = await supabase.from('products').update(data).eq('id', editingItem.id);
      if (!error) {
        setProducts(prev => prev.map(p => p.id === editingItem.id ? { ...p, ...data } : p));
        setIsProductModalOpen(false);
      }
    } else {
      const { data: inserted, error } = await supabase.from('products').insert([data]).select();
      if (!error && inserted) {
        setProducts(prev => [...prev, inserted[0]]);
        setIsProductModalOpen(false);
      }
    }
    setEditingItem(null);
  };

  const handleSlideSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (editingItem) {
      const { error } = await supabase.from('slides').update(slideForm).eq('id', editingItem.id);
      if (!error) {
        setSlides(prev => prev.map(s => s.id === editingItem.id ? { ...s, ...slideForm } : s));
        setIsSlideModalOpen(false);
      }
    } else {
      const { data: inserted, error } = await supabase.from('slides').insert([slideForm]).select();
      if (!error && inserted) {
        setSlides(prev => [...prev, inserted[0]]);
        setIsSlideModalOpen(false);
      }
    }
    setEditingItem(null);
  };

  const deleteProduct = async (id: string) => {
    if (!confirm('আপনি কি নিশ্চিতভাবে এই পণ্যটি মুছে ফেলতে চান?')) return;
    const { error } = await supabase.from('products').delete().eq('id', id);
    if (!error) setProducts(prev => prev.filter(p => p.id !== id));
  };

  const deleteSlide = async (id: string) => {
    if (!confirm('আপনি কি নিশ্চিতভাবে এই স্লাইডটি মুছে ফেলতে চান?')) return;
    const { error } = await supabase.from('slides').delete().eq('id', id);
    if (!error) setSlides(prev => prev.filter(s => s.id !== id));
  };

  const updateOrderStatus = async (id: string, status: string) => {
    const { error } = await supabase.from('orders').update({ status }).eq('id', id);
    if (!error) setOrders(prev => prev.map(o => o.id === id ? { ...o, status: status as any } : o));
  };

  if (!isAuthenticated) {
    return (
      <div className="max-w-md mx-auto my-20 p-10 bg-white rounded-3xl shadow-2xl border border-emerald-100 animate-fade-in">
        <h2 className="text-3xl font-black text-center mb-8 text-emerald-800">অ্যাডমিন প্যানেল</h2>
        <input 
          type="password" 
          className="w-full p-4 border-2 border-gray-100 rounded-2xl mb-6 focus:border-emerald-500 outline-none transition-all font-bold" 
          placeholder="পাসওয়ার্ড" 
          value={password}
          onChange={(e) => setPassword(e.target.value)}
        />
        <button 
          onClick={() => { if (password === 'admin123') setIsAuthenticated(true); else alert('ভুল পাসওয়ার্ড'); }}
          className="w-full bg-emerald-600 text-white py-4 rounded-2xl font-black text-lg shadow-lg shadow-emerald-200 active:scale-95 transition-all"
        >
          প্রবেশ করুন
        </button>
      </div>
    );
  }

  return (
    <div className="max-w-7xl mx-auto px-4 py-8 flex flex-col lg:flex-row gap-8 animate-fade-in">
      {/* Sidebar */}
      <div className="w-full lg:w-64 space-y-2 shrink-0">
        <button onClick={() => setActiveTab('DASHBOARD')} className={`w-full flex items-center gap-3 px-6 py-4 rounded-2xl font-bold transition-all ${activeTab === 'DASHBOARD' ? 'bg-emerald-600 text-white shadow-lg' : 'bg-white hover:bg-emerald-50 text-gray-600'}`}><TrendingUp size={20} /> ড্যাশবোর্ড</button>
        <button onClick={() => setActiveTab('PRODUCTS')} className={`w-full flex items-center gap-3 px-6 py-4 rounded-2xl font-bold transition-all ${activeTab === 'PRODUCTS' ? 'bg-emerald-600 text-white shadow-lg' : 'bg-white hover:bg-emerald-50 text-gray-600'}`}><Package size={20} /> পণ্য তালিকা</button>
        <button onClick={() => setActiveTab('SLIDES')} className={`w-full flex items-center gap-3 px-6 py-4 rounded-2xl font-bold transition-all ${activeTab === 'SLIDES' ? 'bg-emerald-600 text-white shadow-lg' : 'bg-white hover:bg-emerald-50 text-gray-600'}`}><Layout size={20} /> স্লাইডার</button>
        <button onClick={() => setActiveTab('ORDERS')} className={`w-full flex items-center gap-3 px-6 py-4 rounded-2xl font-bold transition-all ${activeTab === 'ORDERS' ? 'bg-emerald-600 text-white shadow-lg' : 'bg-white hover:bg-emerald-50 text-gray-600'}`}><ClipboardList size={20} /> অর্ডারসমূহ</button>
        <hr className="my-6 border-gray-200" />
        <button onClick={() => setIsAuthenticated(false)} className="w-full flex items-center gap-3 px-6 py-4 rounded-2xl font-bold text-red-500 hover:bg-red-50 transition-all"><LogOut size={20} /> লগআউট</button>
      </div>

      {/* Content Area */}
      <div className="flex-grow space-y-6">
        {activeTab === 'DASHBOARD' && (
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <div className="bg-white p-8 rounded-3xl border border-gray-100 shadow-sm">
              <p className="text-gray-400 font-bold text-xs uppercase tracking-widest mb-2">মোট বিক্রয়</p>
              <p className="text-4xl font-black text-emerald-700">৳ {orders.reduce((s, o) => s + o.total, 0)}</p>
            </div>
            <div className="bg-white p-8 rounded-3xl border border-gray-100 shadow-sm">
              <p className="text-gray-400 font-bold text-xs uppercase tracking-widest mb-2">মোট অর্ডার</p>
              <p className="text-4xl font-black">{orders.length}</p>
            </div>
            <div className="bg-white p-8 rounded-3xl border border-gray-100 shadow-sm">
              <p className="text-gray-400 font-bold text-xs uppercase tracking-widest mb-2">পণ্য সংখ্যা</p>
              <p className="text-4xl font-black">{products.length}</p>
            </div>
          </div>
        )}

        {activeTab === 'PRODUCTS' && (
          <div className="bg-white rounded-3xl border border-gray-100 shadow-sm overflow-hidden">
            <div className="p-6 border-b flex justify-between items-center bg-gray-50/50">
              <h3 className="text-xl font-bold text-gray-800">পণ্যের তালিকা</h3>
              <button 
                onClick={() => { setEditingItem(null); setProductForm({name:'', price:'', unit:'কেজি', category: Category.VEGETABLES, image:'', description:'', stock:'100'}); setIsProductModalOpen(true); }}
                className="bg-emerald-600 text-white px-6 py-2.5 rounded-xl text-sm font-bold flex items-center gap-2 hover:bg-emerald-700 transition-all shadow-md"
              >
                <Plus size={18}/> নতুন পণ্য
              </button>
            </div>
            <div className="overflow-x-auto">
              <table className="w-full">
                <thead className="bg-gray-50 text-[10px] font-black text-gray-400 uppercase tracking-widest">
                  <tr><th className="p-6 text-left">নাম</th><th className="p-6 text-left">ক্যাটাগরি</th><th className="p-6 text-right">দাম</th><th className="p-6 text-right">অ্যাকশন</th></tr>
                </thead>
                <tbody className="divide-y divide-gray-100">
                  {products.map(p => (
                    <tr key={p.id} className="hover:bg-gray-50/50 transition-colors">
                      <td className="p-6 font-bold text-gray-700">{p.name}</td>
                      <td className="p-6 text-sm text-gray-500 font-medium">{p.category}</td>
                      <td className="p-6 text-right font-black text-emerald-800">৳ {p.price}</td>
                      <td className="p-6 text-right space-x-2">
                        <button onClick={() => { setEditingItem(p); setProductForm({name:p.name, price:p.price.toString(), unit:p.unit, category:p.category, image:p.image, description:p.description, stock:p.stock.toString()}); setIsProductModalOpen(true); }} className="text-blue-500 hover:bg-blue-50 p-2 rounded-xl transition-all"><Edit size={18}/></button>
                        <button onClick={() => deleteProduct(p.id)} className="text-red-500 hover:bg-red-50 p-2 rounded-xl transition-all"><Trash2 size={18}/></button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}

        {activeTab === 'SLIDES' && (
          <div className="bg-white rounded-3xl border border-gray-100 shadow-sm overflow-hidden">
            <div className="p-6 border-b flex justify-between items-center bg-gray-50/50">
              <h3 className="text-xl font-bold text-gray-800">স্লাইডার ম্যানেজমেন্ট</h3>
              <button 
                onClick={() => { setEditingItem(null); setSlideForm({image:'', title:'', subtitle:'', buttonText:'বাজার শুরু করুন'}); setIsSlideModalOpen(true); }}
                className="bg-emerald-600 text-white px-6 py-2.5 rounded-xl text-sm font-bold flex items-center gap-2"
              >
                <Plus size={18}/> নতুন স্লাইড
              </button>
            </div>
            <div className="p-6 grid grid-cols-1 md:grid-cols-2 gap-6">
              {slides.map(s => (
                <div key={s.id} className="group relative rounded-2xl overflow-hidden border border-gray-100 shadow-sm">
                  <img src={s.image} className="w-full h-40 object-cover opacity-80" alt="" />
                  <div className="p-4">
                    <h4 className="font-bold text-lg">{s.title}</h4>
                    <p className="text-sm text-gray-500 line-clamp-1">{s.subtitle}</p>
                    <div className="mt-4 flex gap-2">
                      <button onClick={() => { setEditingItem(s); setSlideForm({image:s.image, title:s.title, subtitle:s.subtitle, buttonText:s.buttonText}); setIsSlideModalOpen(true); }} className="flex-1 bg-blue-50 text-blue-600 py-2 rounded-xl font-bold text-xs flex justify-center items-center gap-1"><Edit size={14}/> এডিট</button>
                      <button onClick={() => deleteSlide(s.id)} className="flex-1 bg-red-50 text-red-600 py-2 rounded-xl font-bold text-xs flex justify-center items-center gap-1"><Trash2 size={14}/> ডিলিট</button>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {activeTab === 'ORDERS' && (
          <div className="space-y-4">
            {orders.length === 0 ? <p className="text-center py-20 bg-white rounded-3xl border text-gray-400 font-bold">কোনো অর্ডার পাওয়া যায়নি</p> : orders.map(o => (
              <div key={o.id} className="bg-white p-6 rounded-3xl border border-gray-100 shadow-sm flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                <div>
                  <div className="flex items-center gap-3 mb-1">
                    <p className="font-black text-xl text-emerald-900">{o.customerName}</p>
                    <span className={`text-[10px] font-black uppercase px-2 py-1 rounded-full ${o.status === 'Delivered' ? 'bg-emerald-100 text-emerald-600' : 'bg-amber-100 text-amber-600'}`}>
                      {o.status === 'Pending' ? 'অপেক্ষমান' : 'ডেলিভারি সম্পন্ন'}
                    </span>
                  </div>
                  <p className="text-sm text-gray-500 font-bold">{o.phone} • {o.address}</p>
                  <p className="text-xs text-gray-400 mt-1">{new Date(o.date).toLocaleString('bn-BD')}</p>
                </div>
                <div className="text-left md:text-right w-full md:w-auto">
                  <p className="text-2xl font-black text-emerald-800 mb-2">৳ {o.total}</p>
                  {o.status === 'Pending' && (
                    <button 
                      onClick={() => updateOrderStatus(o.id, 'Delivered')} 
                      className="bg-emerald-600 text-white px-6 py-2.5 rounded-xl text-sm font-bold shadow-md shadow-emerald-100 active:scale-95 transition-all"
                    >
                      ডেলিভারি সম্পন্ন করুন
                    </button>
                  )}
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* Product Modal */}
      {isProductModalOpen && (
        <div className="fixed inset-0 z-[100] bg-black/60 backdrop-blur-sm flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-2xl rounded-3xl shadow-2xl overflow-hidden animate-fade-in">
            <div className="p-6 border-b flex justify-between items-center bg-emerald-50">
              <h3 className="font-black text-emerald-900 text-xl">{editingItem ? 'পণ্য সম্পাদনা' : 'নতুন পণ্য যোগ করুন'}</h3>
              <button onClick={() => setIsProductModalOpen(false)} className="p-2 hover:bg-white rounded-full transition-all"><X size={20}/></button>
            </div>
            <form onSubmit={handleProductSubmit} className="p-8 grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-1">
                <label className="text-xs font-bold text-gray-400 uppercase">পণ্যের নাম</label>
                <input required value={productForm.name} onChange={e => setProductForm({...productForm, name: e.target.value})} className="w-full p-3 bg-gray-50 border rounded-xl focus:bg-white outline-none transition-all" />
              </div>
              <div className="space-y-1">
                <label className="text-xs font-bold text-gray-400 uppercase">ক্যাটাগরি</label>
                <select value={productForm.category} onChange={e => setProductForm({...productForm, category: e.target.value as Category})} className="w-full p-3 bg-gray-50 border rounded-xl outline-none">
                  {Object.values(Category).filter(c => c !== Category.ALL).map(c => <option key={c} value={c}>{c}</option>)}
                </select>
              </div>
              <div className="space-y-1">
                <label className="text-xs font-bold text-gray-400 uppercase">দাম (৳)</label>
                <input required type="number" value={productForm.price} onChange={e => setProductForm({...productForm, price: e.target.value})} className="w-full p-3 bg-gray-50 border rounded-xl focus:bg-white outline-none" />
              </div>
              <div className="space-y-1">
                <label className="text-xs font-bold text-gray-400 uppercase">একক (Unit)</label>
                <input required value={productForm.unit} onChange={e => setProductForm({...productForm, unit: e.target.value})} className="w-full p-3 bg-gray-50 border rounded-xl" placeholder="কেজি / লিটার / ডজন" />
              </div>
              <div className="md:col-span-2 space-y-1">
                <label className="text-xs font-bold text-gray-400 uppercase">ছবির লিংক (URL)</label>
                <input required value={productForm.image} onChange={e => setProductForm({...productForm, image: e.target.value})} className="w-full p-3 bg-gray-50 border rounded-xl" placeholder="https://..." />
              </div>
              <div className="md:col-span-2 space-y-1">
                <label className="text-xs font-bold text-gray-400 uppercase">বর্ণনা</label>
                <textarea rows={2} value={productForm.description} onChange={e => setProductForm({...productForm, description: e.target.value})} className="w-full p-3 bg-gray-50 border rounded-xl focus:bg-white outline-none" />
              </div>
              <div className="md:col-span-2 pt-4">
                <button type="submit" className="w-full bg-emerald-600 text-white py-4 rounded-2xl font-black text-lg shadow-xl shadow-emerald-100 flex items-center justify-center gap-2">
                  <Save size={20}/> {editingItem ? 'আপডেট করুন' : 'সেভ করুন'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Slide Modal */}
      {isSlideModalOpen && (
        <div className="fixed inset-0 z-[100] bg-black/60 backdrop-blur-sm flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-xl rounded-3xl shadow-2xl overflow-hidden animate-fade-in">
            <div className="p-6 border-b flex justify-between items-center bg-emerald-50">
              <h3 className="font-black text-emerald-900 text-xl">{editingItem ? 'স্লাইড সম্পাদনা' : 'নতুন স্লাইড'}</h3>
              <button onClick={() => setIsSlideModalOpen(false)}><X size={20}/></button>
            </div>
            <form onSubmit={handleSlideSubmit} className="p-8 space-y-4">
              <div className="space-y-1">
                <label className="text-xs font-bold text-gray-400 uppercase">ছবির লিংক</label>
                <input required value={slideForm.image} onChange={e => setSlideForm({...slideForm, image: e.target.value})} className="w-full p-3 bg-gray-50 border rounded-xl" />
              </div>
              <div className="space-y-1">
                <label className="text-xs font-bold text-gray-400 uppercase">টাইটেল</label>
                <input required value={slideForm.title} onChange={e => setSlideForm({...slideForm, title: e.target.value})} className="w-full p-3 bg-gray-50 border rounded-xl" />
              </div>
              <div className="space-y-1">
                <label className="text-xs font-bold text-gray-400 uppercase">সাব-টাইটেল</label>
                <input value={slideForm.subtitle} onChange={e => setSlideForm({...slideForm, subtitle: e.target.value})} className="w-full p-3 bg-gray-50 border rounded-xl" />
              </div>
              <button type="submit" className="w-full bg-emerald-600 text-white py-4 rounded-2xl font-black text-lg shadow-xl shadow-emerald-100">
                {editingItem ? 'আপডেট' : 'সেভ'} করুন
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminPanel;

import { createClient } from '@supabase/supabase-js';

/**
 * নির্দেশিকা: 
 * ১. Supabase.com এ লগইন করুন।
 * ২. আপনার প্রোজেক্ট সিলেক্ট করুন।
 * ৩. Project Settings > API এ গিয়ে URL এবং anon public key সংগ্রহ করুন।
 * ৪. নিচের ভেরিয়েবল দুটিতে সেই মানগুলো বসিয়ে দিন।
 */
const SUPABASE_URL = 'https://YOUR_PROJECT_URL.supabase.co';
const SUPABASE_ANON_KEY = 'YOUR_ANON_KEY';

export const supabase = createClient(SUPABASE_URL, SUPABASE_ANON_KEY);

import React, { useState } from 'react';
import { Package, ClipboardList, TrendingUp, LogOut, Plus, Trash2, X, Edit, Layout, Save, Database } from 'lucide-react';
import { Product, Order, Slide, Category } from '../types';
import { supabase } from '../supabase';
import { INITIAL_PRODUCTS, INITIAL_SLIDES } from '../data';

interface AdminPanelProps {
  products: Product[];
  setProducts: React.Dispatch<React.SetStateAction<Product[]>>;
  slides: Slide[];
  setSlides: React.Dispatch<React.SetStateAction<Slide[]>>;
  orders: Order[];
  setOrders: React.Dispatch<React.SetStateAction<Order[]>>;
}

const AdminPanel: React.FC<AdminPanelProps> = ({ products, setProducts, slides, setSlides, orders, setOrders }) => {
  const [activeTab, setActiveTab] = useState<'DASHBOARD' | 'PRODUCTS' | 'ORDERS' | 'SLIDES' | 'SETTINGS'>('DASHBOARD');
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [password, setPassword] = useState('');
  const [isSeeding, setIsSeeding] = useState(false);

  // Modals state
  const [isProductModalOpen, setIsProductModalOpen] = useState(false);
  const [isSlideModalOpen, setIsSlideModalOpen] = useState(false);
  const [editingItem, setEditingItem] = useState<any>(null);

  // Form states
  const [productForm, setProductForm] = useState({
    name: '', price: '', unit: 'কেজি', category: Category.VEGETABLES, image: '', description: '', stock: '100'
  });
  const [slideForm, setSlideForm] = useState({
    image: '', title: '', subtitle: '', buttonText: 'বাজার শুরু করুন'
  });

  const seedDatabase = async () => {
    if (!confirm('এটি আপনার ডাটাবেসে ডেমো ডেটা পুশ করবে। আপনি কি নিশ্চিত?')) return;
    setIsSeeding(true);
    try {
      // Seed Products
      const productsToInsert = INITIAL_PRODUCTS.map(({ id, ...rest }) => rest);
      await supabase.from('products').insert(productsToInsert);

      // Seed Slides
      const slidesToInsert = INITIAL_SLIDES.map(({ id, ...rest }) => rest);
      await supabase.from('slides').insert(slidesToInsert);

      alert('সফলভাবে ডেমো ডেটা যুক্ত করা হয়েছে! দয়া করে পেজটি রিফ্রেশ করুন।');
      window.location.reload();
    } catch (error) {
      console.error(error);
      alert('ডেটা যুক্ত করতে সমস্যা হয়েছে। আপনার Supabase টেবিলগুলো ঠিকমতো তৈরি করা আছে কি না চেক করুন।');
    } finally {
      setIsSeeding(false);
