import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { ShoppingCart, Store, Info, Phone, Search, Menu, X, ArrowRight, Settings, CheckCircle, MapPin, Heart } from 'lucide-react';
import { ViewType, Category, Product, CartItem, Order, Slide } from './types';
import { INITIAL_PRODUCTS, INITIAL_SLIDES } from './data';
import { supabase } from './supabase';
import AdminPanel from './components/AdminPanel';
import CartSidebar from './components/CartSidebar';
import ProductCard from './components/ProductCard';

const App: React.FC = () => {
  const [view, setView] = useState<ViewType | 'ORDER_SUCCESS'>('STORE');
  const [products, setProducts] = useState<Product[]>([]);
  const [slides, setSlides] = useState<Slide[]>([]);
  const [orders, setOrders] = useState<Order[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  const [cart, setCart] = useState<CartItem[]>([]);
  const [activeCategory, setActiveCategory] = useState<Category>(Category.ALL);
  const [searchQuery, setSearchQuery] = useState('');
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [currentSlide, setCurrentSlide] = useState(0);

  // Sync data from Supabase
  const refreshData = async () => {
    try {
      const { data: prodData } = await supabase.from('products').select('*');
      const { data: slideData } = await supabase.from('slides').select('*');
      const { data: orderData } = await supabase.from('orders').select('*').order('date', { ascending: false });

      if (prodData && prodData.length > 0) setProducts(prodData);
      else setProducts(INITIAL_PRODUCTS);

      if (slideData && slideData.length > 0) setSlides(slideData);
      else setSlides(INITIAL_SLIDES);

      if (orderData) setOrders(orderData);
    } catch (error) {
      console.error('Error fetching data:', error);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    refreshData();
  }, []);

  useEffect(() => {
    if (view === 'STORE' && slides.length > 0) {
      const timer = setInterval(() => {
        setCurrentSlide(prev => (prev + 1) % slides.length);
      }, 5000);
      return () => clearInterval(timer);
    }
  }, [view, slides.length]);

  const addToCart = useCallback((product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.product.id === product.id);
      if (existing) {
        return prev.map(item => 
          item.product.id === product.id ? { ...item, quantity: item.quantity + 1 } : item
        );
      }
      return [...prev, { product, quantity: 1 }];
    });
    setIsCartOpen(true);
  }, []);

  const removeFromCart = useCallback((productId: string) => {
    setCart(prev => prev.filter(item => item.product.id !== productId));
  }, []);

  const updateQuantity = useCallback((productId: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.product.id === productId) {
        const newQty = Math.max(1, item.quantity + delta);
        return { ...item, quantity: newQty };
      }
      return item;
    }));
  }, []);

  const cartTotal = useMemo(() => cart.reduce((sum, item) => sum + (item.product.price * item.quantity), 0), [cart]);

  const filteredProducts = useMemo(() => {
    return products.filter(p => {
      const matchesCategory = activeCategory === Category.ALL || p.category === activeCategory;
      const matchesSearch = p.name.toLowerCase().includes(searchQuery.toLowerCase());
      return matchesCategory && matchesSearch;
    });
  }, [products, activeCategory, searchQuery]);

  const placeOrder = async (customerData: { name: string, phone: string, address: string }) => {
    const newOrder = {
      customerName: customerData.name,
      phone: customerData.phone,
      address: customerData.address,
      items: cart,
      total: cartTotal,
      status: 'Pending',
      date: new Date().toISOString()
    };

    const { data, error } = await supabase.from('orders').insert([newOrder]).select();

    if (error) {
      alert('অর্ডার সেভ করতে সমস্যা হয়েছে। দয়া করে আপনার ইন্টারনেট কানেকশন চেক করুন।');
    } else {
      setOrders(prev => [data[0], ...prev]);
      setCart([]);
      setView('ORDER_SUCCESS');
    }
  };

  const NavItem: React.FC<{ label: string; viewTarget: ViewType; icon?: React.ReactNode }> = ({ label, viewTarget, icon }) => (
    <button 
      onClick={() => { setView(viewTarget); setIsMobileMenuOpen(false); window.scrollTo(0,0); }}
      className={`flex items-center gap-2 px-4 py-2.5 rounded-xl font-bold transition-all duration-300 ${
        view === viewTarget ? 'text-emerald-700 bg-emerald-50 shadow-sm border border-emerald-100' : 'text-gray-500 hover:text-emerald-600 hover:bg-gray-50'
      }`}
    >
      {icon}
      <span>{label}</span>
    </button>
  );

  if (isLoading) {
    return (
      <div className="h-screen flex flex-col items-center justify-center bg-white">
        <div className="w-16 h-16 border-4 border-emerald-600 border-t-transparent rounded-full animate-spin mb-4"></div>
        <p className="text-emerald-800 font-bold animate-pulse">লোড হচ্ছে...</p>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex flex-col selection:bg-emerald-100">
      {/* Top Banner */}
      <div className="bg-emerald-800 text-white text-[10px] md:text-xs py-2 px-4 text-center font-bold tracking-wider uppercase">
        বদলগাছী সদরে ১ ঘণ্টার মধ্যে হোম ডেলিভারি ফ্রি! আজই অর্ডার করুন।
      </div>

      <header className="sticky top-0 z-40 bg-white/95 backdrop-blur-md border-b shadow-sm">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between items-center h-20 gap-4">
            {/* Logo */}
            <div className="flex items-center gap-4 cursor-pointer shrink-0" onClick={() => setView('STORE')}>
              <div className="bg-emerald-600 p-2.5 rounded-2xl text-white shadow-lg shadow-emerald-100 transition-transform active:scale-90"><Store size={26} /></div>
              <div className="hidden sm:block">
                <h1 className="text-xl font-black text-emerald-900 leading-none">সামসুল'স গ্রোসরি</h1>
                <p className="text-[10px] text-gray-400 font-bold mt-1 flex items-center gap-1 uppercase tracking-tighter"><MapPin size={10}/> বদলগাছী, নওগাঁ</p>
              </div>
            </div>

            {/* Search Bar - Desktop */}
            {view === 'STORE' && (
              <div className="hidden md:flex flex-grow max-w-xl relative group">
                <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 group-focus-within:text-emerald-500 transition-colors" size={18} />
                <input 
                  type="text"
                  placeholder="আপনার প্রিয় পণ্যটি খুঁজুন..."
                  className="w-full bg-gray-50 border-2 border-transparent focus:border-emerald-500 focus:bg-white rounded-2xl py-3 pl-12 pr-4 outline-none transition-all font-medium text-sm shadow-inner"
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                />
              </div>
            )}

            {/* Actions */}
            <div className="flex items-center gap-2 md:gap-4">
              <nav className="hidden lg:flex items-center gap-1">
                <NavItem label="হোম" viewTarget="STORE" icon={<Store size={18} />} />
                <NavItem label="আমাদের কথা" viewTarget="ABOUT" icon={<Info size={18} />} />
                <NavItem label="অ্যাডমিন" viewTarget="ADMIN" icon={<Settings size={18} />} />
              </nav>

              <div className="h-8 w-[1px] bg-gray-200 hidden lg:block mx-2"></div>

              <button 
                onClick={() => setIsCartOpen(true)} 
                className="group relative p-3 text-gray-700 hover:bg-emerald-50 rounded-2xl transition-all active:scale-95"
              >
                <ShoppingCart size={24} className="group-hover:text-emerald-600" />
                {cart.length > 0 && (
                  <span className="absolute -top-1 -right-1 bg-red-500 text-white text-[10px] font-black w-6 h-6 flex items-center justify-center rounded-full border-4 border-white shadow-sm animate-fade-in">
                    {cart.length}
                  </span>
                )}
              </button>

              <button 
                className="lg:hidden p-3 text-gray-700 hover:bg-gray-100 rounded-2xl" 
                onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
              >
                {isMobileMenuOpen ? <X size={24} /> : <Menu size={24} />}
              </button>
            </div>
          </div>
        </div>

        {/* Mobile Search */}
        {view === 'STORE' && (
          <div className="md:hidden px-4 pb-4">
            <div className="relative">
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
              <input 
                type="text"
                placeholder="খুঁজুন..."
                className="w-full bg-gray-50 border rounded-xl py-2.5 pl-11 pr-4 outline-none text-sm"
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
              />
            </div>
          </div>
        )}
      </header>

      {/* Mobile Navigation Drawer */}
      {isMobileMenuOpen && (
        <div className="lg:hidden fixed inset-0 top-20 bg-white z-50 p-6 animate-fade-in border-t shadow-2xl">
          <nav className="flex flex-col gap-3">
            <NavItem label="হোম পেজ" viewTarget="STORE" icon={<Store size={22} />} />
            <NavItem label="আমাদের সম্পর্কে" viewTarget="ABOUT" icon={<Info size={22} />} />
            <NavItem label="অ্যাডমিন প্যানেল" viewTarget="ADMIN" icon={<Settings size={22} />} />
            <div className="mt-8 p-6 bg-emerald-50 rounded-3xl border border-emerald-100">
              <p className="font-black text-emerald-900 mb-2">সাহায্য প্রয়োজন?</p>
              <a href="tel:01700000000" className="flex items-center gap-2 text-emerald-700 font-bold hover:underline"><Phone size={18}/> ০১৭০০-০০০০০০</a>
            </div>
          </nav>
        </div>
      )}

      <main className="flex-grow">
        {view === 'STORE' && (
          <div className="animate-fade-in">
            {/* Hero Slider */}
            <div className="max-w-7xl mx-auto px-4 py-6 sm:px-6 lg:px-8">
              {slides.length > 0 && (
                <div className="relative rounded-[2.5rem] overflow-hidden mb-10 h-72 md:h-[500px] shadow-2xl bg-emerald-900 group">
                  {slides.map((slide, index) => (
                    <div key={slide.id} className={`absolute inset-0 transition-all duration-1000 ease-out ${index === currentSlide ? 'opacity-100 scale-100' : 'opacity-0 scale-105 pointer-events-none'}`}>
                      <img src={slide.image} alt={slide.title} className="w-full h-full object-cover opacity-50" />
                      <div className="absolute inset-0 bg-gradient-to-r from-emerald-950/95 via-emerald-900/40 to-transparent flex flex-col justify-center px-8 md:px-20">
                        <span className="text-emerald-400 font-black text-xs md:text-sm uppercase tracking-[0.4em] mb-4 drop-shadow-lg">সামসুল'স গ্রোসরি স্পেশাল</span>
                        <h2 className="text-3xl md:text-6xl font-black text-white mb-6 leading-tight max-w-2xl drop-shadow-2xl">{slide.title}</h2>
                        <p className="text-emerald-100/90 text-sm md:text-xl mb-10 max-w-lg leading-relaxed font-medium drop-shadow-md">{slide.subtitle}</p>
                        <button 
                          onClick={() => {
                            const productsSection = document.getElementById('products-grid');
                            productsSection?.scrollIntoView({ behavior: 'smooth' });
                          }} 
                          className="bg-white text-emerald-900 px-10 py-4 rounded-2xl font-black w-fit hover:bg-emerald-50 hover:scale-105 active:scale-95 transition-all shadow-xl shadow-black/20"
                        >
                          {slide.buttonText}
                        </button>
                      </div>
                    </div>
                  ))}
                  <div className="absolute bottom-8 left-1/2 -translate-x-1/2 flex gap-3">
                    {slides.map((_, i) => (
                      <button key={i} onClick={() => setCurrentSlide(i)} className={`h-2 rounded-full transition-all duration-500 ${i === currentSlide ? 'w-12 bg-emerald-400' : 'w-3 bg-white/40'}`} />
                    ))}
                  </div>
                </div>
              )}

              {/* Category Filter */}
              <div className="mb-10">
                <div className="flex items-center justify-between mb-8">
                  <h3 className="text-2xl font-black text-gray-900 flex items-center gap-3">
                    <span className="w-2 h-8 bg-emerald-600 rounded-full"></span>
                    ক্যাটাগরি সমূহ
                  </h3>
                </div>
                <div className="flex gap-4 overflow-x-auto no-scrollbar pb-4 -mx-4 px-4">
                  {Object.values(Category).map(cat => (
                    <button
                      key={cat}
                      onClick={() => { setActiveCategory(cat); window.scrollTo({ top: document.getElementById('products-grid')?.offsetTop! - 100, behavior: 'smooth' }); }}
                      className={`px-8 py-3.5 rounded-2xl font-black whitespace-nowrap transition-all border-2 text-sm ${
                        activeCategory === cat 
                        ? 'bg-emerald-600 border-emerald-600 text-white shadow-xl shadow-emerald-200 -translate-y-1' 
                        : 'bg-white border-gray-100 text-gray-500 hover:border-emerald-200 hover:text-emerald-600 hover:shadow-md'
                      }`}
                    >
                      {cat}
                    </button>
                  ))}
                </div>
              </div>

              {/* Product Grid */}
              <div id="products-grid" className="scroll-mt-32">
                <div className="flex items-center justify-between mb-10">
                  <div>
                    <h3 className="text-3xl md:text-4xl font-black text-gray-900 tracking-tight">{activeCategory}</h3>
                    <p className="text-emerald-600 text-sm font-bold mt-2 uppercase tracking-[0.2em]">{filteredProducts.length} টি তাজা পণ্য আপনার জন্য</p>
                  </div>
                </div>

                {filteredProducts.length > 0 ? (
                  <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 xl:grid-cols-6 gap-4 md:gap-8">
                    {filteredProducts.map(product => (
                      <ProductCard key={product.id} product={product} onAddToCart={addToCart} />
                    ))}
                  </div>
                ) : (
                  <div className="py-24 text-center bg-white rounded-[4rem] border-4 border-dashed border-gray-100 shadow-inner">
                    <Search className="mx-auto text-gray-200 mb-6" size={80} strokeWidth={1} />
                    <p className="text-2xl font-black text-gray-400 mb-2">দুঃখিত, কোনো পণ্য পাওয়া যায়নি!</p>
                    <p className="text-gray-400 font-medium mb-8">অন্য কোনো ক্যাটাগরি বা নাম দিয়ে চেষ্টা করুন।</p>
                    <button onClick={() => { setActiveCategory(Category.ALL); setSearchQuery(''); }} className="bg-emerald-600 text-white px-8 py-3 rounded-2xl font-black shadow-lg shadow-emerald-100">সব পণ্য দেখুন</button>
                  </div>
                )}
              </div>
            </div>

            {/* Features section */}
            <div className="bg-emerald-50 py-24 mt-20 border-y border-emerald-100">
              <div className="max-w-7xl mx-auto px-4 grid grid-cols-1 md:grid-cols-3 gap-16">
                <div className="text-center group">
                  <div className="w-20 h-20 bg-white rounded-[2rem] flex items-center justify-center mx-auto mb-8 shadow-xl text-emerald-600 group-hover:scale-110 transition-transform"><CheckCircle size={40}/></div>
                  <h4 className="text-2xl font-black mb-3 text-emerald-900">১০০% টাটকা পণ্য</h4>
                  <p className="text-emerald-800/60 font-medium leading-relaxed">আমরা সরাসরি স্থানীয় বাগান এবং খামারিদের থেকে পণ্য সংগ্রহ করি। গুণগত মানে কোনো আপস নয়।</p>
                </div>
                <div className="text-center group">
                  <div className="w-20 h-20 bg-white rounded-[2rem] flex items-center justify-center mx-auto mb-8 shadow-xl text-emerald-600 group-hover:scale-110 transition-transform"><MapPin size={40}/></div>
                  <h4 className="text-2xl font-black mb-3 text-emerald-900">দ্রুত ডেলিভারি</h4>
                  <p className="text-emerald-800/60 font-medium leading-relaxed">বদলগাছী সদরে আপনার দোরগোড়ায় মাত্র ১ ঘণ্টার মধ্যে হোম ডেলিভারি পৌঁছে দিবে আমাদের টিম।</p>
                </div>
                <div className="text-center group">
                  <div className="w-20 h-20 bg-white rounded-[2rem] flex items-center justify-center mx-auto mb-8 shadow-xl text-emerald-600 group-hover:scale-110 transition-transform"><Phone size={40}/></div>
                  <h4 className="text-2xl font-black mb-3 text-emerald-900">২৪/৭ কাস্টমার সাপোর্ট</h4>
                  <p className="text-emerald-800/60 font-medium leading-relaxed">যে কোনো জিজ্ঞাসা বা সমস্যার সমাধানে আমাদের ফোন করুন ০১৭০০-০০০০০০ নম্বরে।</p>
                </div>
              </div>
            </div>
          </div>
        )}

        {view === 'ABOUT' && (
          <div className="max-w-4xl mx-auto py-20 px-6 animate-fade-in">
            <div className="text-center mb-16">
              <h2 className="text-5xl font-black text-emerald-900 mb-6 tracking-tight">আমাদের সম্পর্কে</h2>
              <div className="w-20 h-2 bg-emerald-500 mx-auto rounded-full mb-8"></div>
              <p className="text-xl text-gray-600 leading-relaxed font-medium">বদলগাছীর সাধারণ মানুষের নিত্যদিনের বাজারকে সহজ ও আধুনিক করতে আমাদের পথচলা।</p>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-12 mb-20">
              <div className="bg-white p-10 rounded-[3rem] shadow-xl border border-gray-100">
                <h3 className="text-2xl font-black text-emerald-800 mb-4 flex items-center gap-2"><Heart className="text-red-500" fill="currentColor" size={24}/> আমাদের লক্ষ্য</h3>
                <p className="text-gray-500 font-medium leading-relaxed">আমরা চাই প্রতিটি ঘরে পৌঁছে যাক টাটকা ও বিষমুক্ত খাদ্য। মধ্যস্বত্বভোগীদের দৌরাত্ম্য কমিয়ে সরাসরি কৃষক থেকে পণ্য এনে আপনাদের দেওয়া আমাদের প্রধান লক্ষ্য।</p>
              </div>
              <div className="bg-white p-10 rounded-[3rem] shadow-xl border border-gray-100">
                <h3 className="text-2xl font-black text-emerald-800 mb-4 flex items-center gap-2"><Store className="text-emerald-600" size={24}/> কেন আমাদের বেছে নেবেন?</h3>
                <p className="text-gray-500 font-medium leading-relaxed">সততা এবং গুণগত মানই আমাদের মূল শক্তি। আমরা শুধুমাত্র একটি ব্যবসা নই, আমরা একটি পরিবার। আপনার সন্তুষ্টিই আমাদের সার্থকতা।</p>
              </div>
            </div>

            <div className="bg-emerald-900 rounded-[3.5rem] p-12 text-white text-center shadow-2xl relative overflow-hidden">
               <div className="absolute top-0 right-0 w-64 h-64 bg-emerald-800 rounded-full -translate-y-1/2 translate-x-1/2 opacity-20"></div>
               <h3 className="text-3xl font-black mb-6 relative z-10">আপনার কোনো অভিযোগ বা পরামর্শ আছে?</h3>
               <p className="text-emerald-100 mb-10 text-lg font-medium relative z-10">আমরা সবসময় আপনাদের কথা শুনতে আগ্রহী। সরাসরি কল করুন আমাদের হটলাইনে।</p>
               <a href="tel:01700000000" className="inline-flex items-center gap-3 bg-white text-emerald-900 px-10 py-5 rounded-2xl font-black text-xl hover:bg-emerald-50 transition shadow-xl relative z-10"><Phone size={24}/> ০১৭০০-০০০০০০</a>
            </div>
          </div>
        )}

        {view === 'ADMIN' && (
          <AdminPanel 
            products={products} setProducts={setProducts} 
            slides={slides} setSlides={setSlides}
            orders={orders} setOrders={setOrders}
          />
        )}

        {view === 'CHECKOUT' && (
          <div className="max-w-xl mx-auto py-20 px-4 animate-fade-in">
            <h2 className="text-4xl font-black mb-4 text-center text-emerald-900">চেকআউট</h2>
            <p className="text-center text-gray-500 mb-10 font-medium">আপনার সঠিক তথ্য দিয়ে অর্ডারটি সম্পন্ন করুন।</p>
            <form onSubmit={(e) => {
              e.preventDefault();
              const fd = new FormData(e.currentTarget);
              placeOrder({
                name: fd.get('name') as string,
                phone: fd.get('phone') as string,
                address: fd.get('address') as string,
              });
            }} className="bg-white p-10 rounded-[3rem] shadow-2xl shadow-emerald-100/50 border border-emerald-50 space-y-6">
              <div className="space-y-2">
                <label className="text-xs font-black text-gray-400 uppercase tracking-widest ml-1">আপনার সম্পূর্ণ নাম</label>
                <input name="name" required className="w-full p-4 bg-gray-50 border-2 border-transparent focus:border-emerald-500 focus:bg-white rounded-2xl outline-none transition-all font-bold" placeholder="যেমন: রহিম হোসেন" />
              </div>
              <div className="space-y-2">
                <label className="text-xs font-black text-gray-400 uppercase tracking-widest ml-1">সক্রিয় মোবাইল নম্বর</label>
                <input name="phone" required type="tel" className="w-full p-4 bg-gray-50 border-2 border-transparent focus:border-emerald-500 focus:bg-white rounded-2xl outline-none transition-all font-bold" placeholder="০১৭XXXXXXXX" />
              </div>
              <div className="space-y-2">
                <label className="text-xs font-black text-gray-400 uppercase tracking-widest ml-1">ডেলিভারি ঠিকানা</label>
                <textarea name="address" required className="w-full p-4 bg-gray-50 border-2 border-transparent focus:border-emerald-500 focus:bg-white rounded-2xl outline-none transition-all font-bold" placeholder="আপনার গ্রাম, পাড়া বা বাড়ির নাম লিখুন" rows={3}></textarea>
              </div>

              <div className="pt-6 border-t border-dashed border-gray-200">
                <div className="flex justify-between items-center mb-6 px-2">
                  <span className="text-gray-500 font-bold">মোট দেয় পরিমাণ:</span>
                  <span className="text-3xl font-black text-emerald-800 tracking-tight">৳ {cartTotal}</span>
                </div>
                <button className="w-full bg-emerald-600 text-white py-5 rounded-2xl font-black text-xl shadow-xl shadow-emerald-200 hover:bg-emerald-700 active:scale-95 transition-all">
                  অর্ডার সম্পন্ন করুন
                </button>
                <p className="text-center text-[10px] text-gray-400 mt-6 font-bold uppercase tracking-[0.2em] leading-relaxed">
                  * বর্তমানে শুধুমাত্র ক্যাশ অন ডেলিভারি প্রযোজ্য <br/> পণ্য হাতে পেয়ে মূল্য পরিশোধ করবেন।
                </p>
              </div>
            </form>
          </div>
        )}

        {view === 'ORDER_SUCCESS' && (
          <div className="max-w-2xl mx-auto py-32 px-4 text-center animate-fade-in">
            <div className="w-32 h-32 bg-emerald-100 text-emerald-600 rounded-[2.5rem] flex items-center justify-center mx-auto mb-10 shadow-2xl animate-bounce">
              <CheckCircle size={72} strokeWidth={2.5} />
            </div>
            <h2 className="text-5xl md:text-6xl font-black text-emerald-900 mb-6 leading-tight tracking-tight">অর্ডার সফল হয়েছে!</h2>
            <p className="text-gray-500 text-xl md:text-2xl mb-12 font-medium leading-relaxed max-w-lg mx-auto">ধন্যবাদ! আপনার অর্ডারটি গৃহিত হয়েছে। আমরা খুব শীঘ্রই ডেলিভারির জন্য আপনার সাথে যোগাযোগ করব।</p>
            <div className="flex flex-col sm:flex-row gap-6 justify-center">
              <button 
                onClick={() => setView('STORE')} 
                className="bg-emerald-600 text-white px-12 py-5 rounded-2xl font-black text-xl shadow-xl shadow-emerald-200 hover:bg-emerald-700 transition-all active:scale-95"
              >
                আরো বাজার করুন
              </button>
              <a 
                href="tel:01700000000" 
                className="bg-white border-2 border-emerald-600 text-emerald-600 px-12 py-5 rounded-2xl font-black text-xl hover:bg-emerald-50 transition-all active:scale-95 shadow-md"
              >
                কল করুন
              </a>
            </div>
          </div>
        )}
      </main>

      <footer className="bg-gray-950 text-white pt-24 pb-12">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="grid grid-cols-1 md:grid-cols-4 gap-16 mb-24">
            <div className="col-span-1 md:col-span-2">
              <div className="flex items-center gap-4 mb-8">
                <div className="bg-emerald-600 p-2.5 rounded-xl text-white"><Store size={28} /></div>
                <h1 className="text-3xl font-black tracking-tight">সামসুল'স গ্রোসরি</h1>
              </div>
              <p className="text-gray-400 font-medium max-w-sm leading-relaxed mb-8 text-lg">বদলগাছীর সাধারণ মানুষের জন্য তৈরি একটি আধুনিক অনলাইন গ্রোসরি প্ল্যাটফর্ম। আমরা বিশ্বাস করি টাটকা খাবারই সুস্বাস্থ্যের চাবিকাঠি।</p>
              <div className="flex gap-4">
                <div className="w-12 h-12 bg-white/5 rounded-2xl flex items-center justify-center hover:bg-emerald-600 transition-all cursor-pointer border border-white/10"><Info size={24}/></div>
                <div className="w-12 h-12 bg-white/5 rounded-2xl flex items-center justify-center hover:bg-emerald-600 transition-all cursor-pointer border border-white/10"><Phone size={24}/></div>
              </div>
            </div>
            <div>
              <h4 className="font-black text-xl mb-8 text-emerald-400 uppercase tracking-widest">গুরুত্বপূর্ণ লিংক</h4>
              <ul className="space-y-4 text-gray-400 font-bold">
                <li><button onClick={() => setView('STORE')} className="hover:text-emerald-400 transition-colors">হোম পেজ</button></li>
                <li><button onClick={() => setView('ABOUT')} className="hover:text-emerald-400 transition-colors">আমাদের সম্পর্কে</button></li>
                <li><button className="hover:text-emerald-400 transition-colors">কিভাবে অর্ডার করবেন?</button></li>
                <li><button className="hover:text-emerald-400 transition-colors">রিফান্ড পলিসি</button></li>
              </ul>
            </div>
            <div>
              <h4 className="font-black text-xl mb-8 text-emerald-400 uppercase tracking-widest">যোগাযোগ</h4>
              <ul className="space-y-5 text-gray-400 font-bold text-sm">
                <li className="flex items-start gap-3"><MapPin size={20} className="text-emerald-500 shrink-0"/> বদলগাছী বাজার, বদলগাছী, নওগাঁ</li>
                <li className="flex items-start gap-3"><Phone size={20} className="text-emerald-500 shrink-0"/> ০১৭০০-০০০০০০</li>
                <li className="flex items-start gap-3"><Info size={20} className="text-emerald-500 shrink-0"/> প্রতিদিন সকাল ৮টা - রাত ১০টা</li>
              </ul>
            </div>
          </div>
          <div className="pt-12 border-t border-white/5 text-center text-gray-500 text-xs font-bold uppercase tracking-[0.3em] leading-relaxed">
            &copy; ২০২৪ সামসুল'স গ্রোসরি | সকল স্বত্ব সংরক্ষিত <br/>
            <span className="text-[10px] opacity-50 mt-2 block">বদলগাছী, নওগাঁ, বাংলাদেশ</span>
          </div>
        </div>
      </footer>

      <CartSidebar 
        isOpen={isCartOpen} onClose={() => setIsCartOpen(false)} 
        cart={cart} updateQuantity={updateQuantity} 
        removeFromCart={removeFromCart} onCheckout={() => { setIsCartOpen(false); setView('CHECKOUT'); }} 
      />
    </div>
  );
};

export default App;
